AS `no_of_spindle`,`runprod`.`tpi` AS `tpi`,`runprod`.`netmins` AS `netmins` from (select `pds`.`doff_date` AS `doff_date`,date_format(`pds`.`doff_date`,'%d-%m-%Y') AS `report_date`,`pds`.`shift_id` AS `spell_id`,`pds`.`shift_name` AS `shift_name`,`heod`.`emp_code` AS `emp_code`,case when `hepd`.`eb_id` is null then NULL else concat(`hepd`.`first_name`,ifnull(`hepd`.`middle_name`,''),ifnull(`hepd`.`last_name`,'')) end AS `emp_name`,`pds`.`machine_name` AS `frame_no`,`pds`.`std_count` AS `count`,round(`pds`.`working_hours`,2) AS `power_min`,round(`pds`.`noofdoff` * 2,2) AS `loss_d`,round(`pds`.`loss_min_mech`,2) AS `loss_m`,round(`pds`.`loss_min_elec`,2) AS `loss_e`,round(`pds`.`loss_min_oth`,2) AS `loss_i`,round(coalesce(`pds`.`loss_min_doff`,0) + coalesce(`pds`.`loss_min_mech`,0) + coalesce(`pds`.`loss_min_elec`,0) + coalesce(`pds`.`loss_min_oth`,0),2) AS `total_loss`,round(`pds`.`netmins`,2) AS `actual_run`,`pds`.`mc_runs_time` AS `As_per_VVfd`,`pds`.`noofdoff` AS `machine_doff`,round(`pds`.`weight`,2) AS `doff_wt`,`pds`.`speed` AS `rpm`,round(`pds`.`speed` * `pds`.`std_count` * `pds`.`no_of_spindle` * `pds`.`working_hours` / (`pds`.`tpi` * 14400 * 36 * 2.2046),0) AS `eff_100`,round(`pds`.`weight` / (`pds`.`speed` * `pds`.`std_count` * `pds`.`no_of_spindle` * `pds`.`whours` / (`pds`.`tpi` * 14400 * 36 * 2.2046)) * 100,2) AS `actual_eff`,`pds`.`whours` AS `whours`,`pds`.`loss` AS `loss`,`pds`.`totrun` AS `totrun`,`pds`.`tstop` + `pds`.`loss_min_idle` AS `tstop`,`pds`.`mcrunmins` AS `mcrunmins`,`pds`.`loss_min_idle` AS `loss_min_idle`,`pds`.`no_of_spindle` AS `no_of_spindle`,`pds`.`netmins` AS `netmins`,`pds`.`tpi` AS `tpi` from (((select `pd`.`doff_date` AS `doff_date`,`pd`.`shift_id` AS `shift_id`,`pd`.`mc_id` AS `mc_id`,`pd`.`eb_id` AS `eb_id`,`pd`.`quality_id` AS `quality_id`,sum(`pd`.`noofdoff`) AS `noofdoff`,sum(`pd`.`weight`) AS `weight`,`sfm`.`shift_name` AS `shift_name`,`mm`.`machine_name` AS `machine_name`,`fdm`.`speed` AS `speed`,`sqm`.`std_count` AS `std_count`,sum(`vvfd`.`mc_runs_time`) AS `mc_runs_time`,sum(`vvfd`.`clossmindoff`) AS `loss_min_doff`,sum(`vvfd`.`loss_min_elec`) AS `loss_min_elec`,sum(`vvfd`.`loss_min_mech`) AS `loss_min_mech`,sum(`vvfd`.`loss_min_oth`) AS `loss_min_oth`,sum(`sfm`.`working_hours` * 60 - coalesce(`vvfd`.`stopmins`,0)) AS `working_hours`,sum(`sfm`.`working_hours` * 60 - coalesce(`vvfd`.`stopmins`,0) - (coalesce(`vvfd`.`clossmindoff`,0) + coalesce(`vvfd`.`loss_min_elec`,0) + coalesce(`vvfd`.`loss_min_mech`,0) + coalesce(`vvfd`.`loss_min_oth`,0))) AS `netmins`,`sqm`.`tpi` AS `tpi`,`fdm`.`no_of_spindle` AS `no_of_spindle`,sum(`vvfd`.`idlehrs`) AS `loss_min_idle`,sum(`vvfd`.`whours` - coalesce(`vvfd`.`stopmins`,0)) AS `whours`,sum(`vvfd`.`loss`) AS `loss`,sum(`vvfd`.`totrun`) AS `totrun`,sum(`vvfd`.`tstop`) AS `tstop`,sum(`vvfd`.`mcrunmins`) AS `mcrunmins` from ((((((select `ddt`.`doff_date` AS `doff_date`,`sm`.`spell_id` AS `spell_id`,`sm`.`shift_id` AS `shift_id`,`ddt`.`mc_id` AS `mc_id`,`ddfw`.`eb_id` AS `eb_id`,`ddfw`.`quality_id` AS `quality_id`,count(0) AS `noofdoff`,sum(`ddt`.`net_weight`) AS `weight` from ((`daily_doff_tbl` `ddt` left join `daily_doff_frames_winding` `ddfw` on(`ddt`.`doff_date` = `ddfw`.`tran_date` and `ddt`.`spell` = `ddfw`.`spell` and `ddt`.`mc_id` = `ddfw`.`mc_eb_id`)) left join `spell_mst` `sm` on(`sm`.`spell_id` = `ddt`.`spell`)) group by `ddt`.`doff_date`,`sm`.`spell_id`,`sm`.`shift_id`,`ddt`.`mc_id`,`ddfw`.`eb_id`,`ddfw`.`quality_id`) `pd` left join `view_vvfd__prod_trans` `vvfd` on(`pd`.`doff_date` = `vvfd`.`tran_date` and `pd`.`spell_id` = `vvfd`.`spell_id` and `pd`.`mc_id` = `vvfd`.`mc_id`)) left join `shift_mst` `sfm` on(`sfm`.`shift_id` = `pd`.`shift_id`)) left join `machine_mst` `mm` on(`mm`.`machine_id` = `pd`.`mc_id`)) left join `frame_details_mst` `fdm` on(`fdm`.`mc_id` = `pd`.`mc_id`)) left join `spinning_quality_mst` `sqm` on(`sqm`.`spg_quality_mst_id` = `pd`.`quality_id`)) group by `pd`.`doff_date`,`pd`.`shift_id`,`pd`.`mc_id`,`pd`.`eb_id`,`pd`.`quality_id`,`sfm`.`shift_name`,`mm`.`machine_name`,`fdm`.`speed`,`sqm`.`std_count`,`sqm`.`tpi`,`fdm`.`no_of_spindle`) `pds` left join `hrms_ed_official_details` `heod` on(`pds`.`eb_id` = `heod`.`eb_id` and `heod`.`active` = 1)) left join `hrms_ed_personal_details` `hepd` on(`pds`.`eb_id` = `hepd`.`eb_id`))) `runprod`;
